// isVideoMIME / isAudioMIME / isEmbeddableMIME classify a MIME for the
// inline-preview branches. Kept as slice checks to match the existing
// isImageMIME helper and avoid a strings import.
func isVideoMIME(mime string) bool { return len(mime) >= 6 && mime[:6] == "video/" }

func isAudioMIME(mime string) bool { return len(mime) >= 6 && mime[:6] == "audio/" }

func isEmbeddableMIME(mime string) bool {
	return isImageMIME(mime) || isVideoMIME(mime) || isAudioMIME(mime) || mime == "application/pdf"
}

// AttachmentGroup is one bucket rendered by projectAttachmentsByCategory.
type AttachmentGroup struct {
	Category string
	Items    []ProjectAttachmentView
}

func groupAttachmentsByCategory(atts []ProjectAttachmentView) []AttachmentGroup {
	bucket := map[string][]ProjectAttachmentView{}
	order := []string{}
	for _, a := range atts {
		cat := a.Category
		if cat == "" {
			cat = "common"
		}
		if _, ok := bucket[cat]; !ok {
			order = append(order, cat)
		}
		bucket[cat] = append(bucket[cat], a)
	}
	// Pin common first if present, then the rest in insertion order.
	sorted := make([]string, 0, len(order))
	if _, ok := bucket["common"]; ok {
		sorted = append(sorted, "common")
	}
	for _, k := range order {
		if k != "common" {
			sorted = append(sorted, k)
		}
	}
	out := make([]AttachmentGroup, 0, len(sorted))
	for _, k := range sorted {
		out = append(out, AttachmentGroup{Category: k, Items: bucket[k]})
	}
	return out
}

func categoryLabel(c string) string {
	switch c {
	case "common":
		return "Common"
	case "api_docs":
		return "API docs"
	case "design":
		return "Design"
	case "specs":
		return "Specs"
	case "other":
		return "Other"
	default:
		return c
	}
}

// projectTodoStatusLabel maps a project-todo status to its human label.
